+    let streaming_len: usize = (0..token_count)
+        .map(|i| format!("token-{i} ").len())
+        .sum();
+
+    log_perf_test_event(
+        "tui_perf_e2e_streaming_with_history",
+        "streaming_performance",
+        json!({
